package commands

import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcUserTopicProgressRepository struct {
	sqrc db.Querier
}

func NewSqrcUserTopicProgressRepository(q db.Querier) *SqrcUserTopicProgressRepository {
	return &SqrcUserTopicProgressRepository{sqrc: q}
}

func (repository *SqrcUserTopicProgressRepository) getProgress(ctx context.Context, userId string, courseId string) (Progress, error) {
	var userIdUuid, courseIdUuid pgtype.UUID

	if err := userIdUuid.Scan(userId); err != nil {
		return Progress{}, err
	}
	if err := courseIdUuid.Scan(courseId); err != nil {
		return Progress{}, err
	}

	rows, err := repository.sqrc.GetProgressByUserIdAndCourseId(ctx, db.GetProgressByUserIdAndCourseIdParams{
		Userid:   userIdUuid,
		Courseid: courseIdUuid,
	})
	if err != nil {
		return Progress{}, err
	}

	records := make([]ProgressRecord, len(rows))
	for i, row := range rows {
		records[i] = ProgressRecord{
			courseSectionTopicId: row.CourseSectionTopicID.String(),
			sectionNumber:        int(row.SectionIndex),
			topicNumber:          int(row.TopicIndex),
			status:               row.Status,
		}
	}

	return Progress{courseId: courseId, userId: userId, records: records}, nil
}

func (repository *SqrcUserTopicProgressRepository) save(ctx context.Context, progress *Progress) error {
	for _, record := range progress.records {
		var topicIdUuid, userIdUuid pgtype.UUID
		if err := topicIdUuid.Scan(record.courseSectionTopicId); err != nil {
			return err
		}
		if err := userIdUuid.Scan(progress.userId); err != nil {
			return err
		}

		if err := repository.sqrc.UpsertProgress(ctx, db.UpsertProgressParams{
			Coursesectiontopicid: topicIdUuid,
			Userid:               userIdUuid,
			Status:               record.status,
		}); err != nil {
			return err
		}
	}
	return nil
}

package commands

import (
	"context"
	"encoding/json"
	"time"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcCourseRepository struct {
	sqrc db.Querier
}

func NewSqrcCourseRepository(q db.Querier) *SqrcCourseRepository {
	return &SqrcCourseRepository{sqrc: q}
}

func (repository *SqrcCourseRepository) getCourseByCourseId(ctx context.Context, courseId string) (Course, error) {
	var courseIdUuid pgtype.UUID

	if err := courseIdUuid.Scan(courseId); err != nil {
		return Course{}, err
	}

	courseRaw, err := repository.sqrc.GetCourseById(ctx, courseIdUuid)
	if err != nil {
		return Course{}, err
	}

	return toCourse(courseRaw), nil
}

func toCourse(raw db.GetCourseByIdRow) Course {
	var tags []string
	json.Unmarshal(raw.Tags, &tags)

	type topicRaw struct {
		CourseSectionTopicId string `json:"course_section_topic_id"`
		Title                string `json:"title"`
		Description          string `json:"description"`
		Prerequisites        string `json:"prerequisites"`
		Knowledge            string `json:"knowledge"`
		Flow                 string `json:"flow"`
		Quiz                 string `json:"quiz"`
		CompletionCriteria   string `json:"completion_criteria"`
	}
	type sectionRaw struct {
		CourseSectionId string     `json:"course_section_id"`
		Title           string     `json:"title"`
		Description     string     `json:"description"`
		Topics          []topicRaw `json:"topics"`
	}

	var sectionsRaw []sectionRaw
	json.Unmarshal(raw.Sections, &sectionsRaw)

	sections := make([]Section, len(sectionsRaw))
	for i, s := range sectionsRaw {
		topics := make([]Topic, len(s.Topics))
		for j, t := range s.Topics {
			topics[j] = Topic{
				topicId:            t.CourseSectionTopicId,
				title:              t.Title,
				description:        t.Description,
				prerequisites:      t.Prerequisites,
				knowledge:          t.Knowledge,
				flow:               t.Flow,
				quiz:               t.Quiz,
				completionCriteria: t.CompletionCriteria,
				number:             j,
			}
		}
		sections[i] = Section{
			sectionId:   s.CourseSectionId,
			title:       s.Title,
			description: s.Description,
			number:      i,
			topics:      topics,
		}
	}

	var publishedAt *string
	if raw.PublishedAt.Valid {
		t := raw.PublishedAt.Time.Format(time.RFC3339)
		publishedAt = &t
	}

	return Course{
		courseId:      raw.CourseID.String(),
		title:         raw.Title,
		description:   raw.Description,
		slug:          raw.Slug,
		tags:          tags,
		publishStatus: raw.PublishStatus,
		category: Category{
			categoryId: raw.CategoryID.String(),
			name:       raw.CategoryName,
		},
		publishedAt: publishedAt,
		author: Author{
			authorId: raw.AuthorID.String(),
			name:     raw.AuthorName,
		},
		visibility: raw.Visibility,
		sections:   sections,
	}
}

CREATE EXTENSION ltree;

CREATE FUNCTION update_meta_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW._updated_at := NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TABLE categories (
    category_id UUID,
    name TEXT NOT NULL,
    path ltree NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_categories PRIMARY KEY (category_id)
);

CREATE INDEX idx_categories_path ON categories USING gist (path);

CREATE TABLE authors (
    author_id UUID,
    name TEXT NOT NULL,
    profile TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_authors PRIMARY KEY (author_id)
);

CREATE TABLE courses (
    course_id UUID,
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    slug TEXT NOT NULL,
    tags JSONB NOT NULL,
    publish_status TEXT NOT NULL,
    category_id UUID NOT NULL,
    published_at TIMESTAMPTZ,
    author_id UUID NOT NULL,
    visibility TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_courses PRIMARY KEY (course_id),
    CONSTRAINT fk_courses_category_id FOREIGN KEY (category_id) REFERENCES categories(category_id),
    CONSTRAINT fk_courses_author_id FOREIGN KEY (author_id) REFERENCES authors(author_id),
    CONSTRAINT uq_courses_slug_author_id UNIQUE (slug, author_id)
);

CREATE INDEX idx_courses_category_id ON courses USING btree (category_id);
CREATE INDEX idx_courses_author_id ON courses USING btree (author_id);
CREATE INDEX idx_courses_tags ON courses USING gin (tags);

COMMENT ON COLUMN courses.publish_status IS 'draft / published / archived';
COMMENT ON COLUMN courses.visibility IS 'private = 自分のみ, public = 誰でも閲覧可, paid = 購入者のみ';

CREATE TRIGGER trigger_courses_meta_updated_at
    BEFORE UPDATE ON courses
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

CREATE TRIGGER trigger_categories_meta_updated_at
    BEFORE UPDATE ON categories
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

CREATE TRIGGER trigger_authors_meta_updated_at
    BEFORE UPDATE ON authors
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

